import (
    "github.com/openmeterio/openmeter/pkg/kafka"
    "go.opentelemetry.io/otel/metric/noop"
    "time"
)

cfg := kafka.ConsumerConfig{
    CommonConfigParams: kafka.CommonConfigParams{
        Brokers:       "broker:9092",
        StatsInterval: kafka.TimeDurationMilliSeconds(10 * time.Second),
        TopicMetadataRefreshInterval: kafka.TimeDurationMilliSeconds(30 * time.Second),
    },
    ConsumerConfigParams: kafka.ConsumerConfigParams{
        ConsumerGroupID: "my-group",
        AutoOffsetReset: kafka.AutoOffsetResetEarliest,
        PartitionAssignmentStrategy: kafka.PartitionAssignmentStrategies{
            kafka.PartitionAssignmentStrategyCooperativeSticky,
        },
    },
}
if err := cfg.Validate(); err != nil {
    return err
}
configMap, err := cfg.AsConfigMap()
if err != nil {
    return err
}

provisioner, err := kafka.NewTopicProvisioner(kafka.TopicProvisionerConfig{
    AdminClient:     adminClient,
    Logger:          logger,
    Meter:           noop.NewMeterProvider().Meter("test"),
    CacheSize:       200,
    CacheTTL:        5 * time.Minute,
    ProtectedTopics: []string{"system-events"},
})
if err != nil {
    return err
}
err = provisioner.Provision(ctx, kafka.TopicConfig{
    Name:       "my-namespace.ingest",
    Partitions: 4,
    Replicas:   1,
})
